import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function Login() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      await login(form.email, form.password);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed. Check your email and password.');
    }
    setLoading(false);
  };

  return (
    <div style={{minHeight:'100vh',display:'flex',background:'#0a0d14'}}>
      {/* Left Panel */}
      <div style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',background:'linear-gradient(135deg, #0f1320 0%, #141826 100%)',borderRight:'1px solid #252d47',padding:'3rem',position:'relative',overflow:'hidden'}}>
        <div style={{position:'absolute',top:-100,left:-100,width:400,height:400,borderRadius:'50%',background:'radial-gradient(circle, rgba(108,99,255,0.08) 0%, transparent 70%)'}} />
        <div style={{position:'absolute',bottom:-50,right:-50,width:300,height:300,borderRadius:'50%',background:'radial-gradient(circle, rgba(0,212,170,0.06) 0%, transparent 70%)'}} />

        <div style={{textAlign:'center',zIndex:1}}>
          <div style={{width:80,height:80,borderRadius:20,background:'linear-gradient(135deg, #6c63ff, #00d4aa)',display:'flex',alignItems:'center',justifyContent:'center',margin:'0 auto 1.5rem',fontSize:'2rem',boxShadow:'0 8px 32px rgba(108,99,255,0.3)'}}>⟡</div>
          <h1 style={{fontWeight:900,fontSize:'2.5rem',marginBottom:'0.5rem',background:'linear-gradient(135deg, #e8eaf0, #9aa3bf)',WebkitBackgroundClip:'text',WebkitTextFillColor:'transparent'}}>SIST</h1>
          <h2 style={{fontWeight:800,fontSize:'1.5rem',color:'#6c63ff',marginBottom:'1rem',letterSpacing:'-0.5px'}}>SkillConnect</h2>
          <p style={{color:'#9aa3bf',fontSize:'1rem',maxWidth:320,lineHeight:1.7}}>Sathyabama Institute of Science and Technology's Research Collaboration Platform</p>

          <div style={{marginTop:'3rem',display:'flex',flexDirection:'column',gap:'1rem'}}>
            {[
              {icon:'🎓', text:'Students find research opportunities'},
              {icon:'👨‍🏫', text:'Faculty post and manage projects'},
              {icon:'🔗', text:'Smart skill matching algorithm'},
              {icon:'📬', text:'Seamless request & notification system'},
            ].map((item,i) => (
              <div key={i} style={{display:'flex',alignItems:'center',gap:'12px',padding:'12px 16px',background:'rgba(255,255,255,0.03)',borderRadius:10,border:'1px solid rgba(255,255,255,0.05)',textAlign:'left'}}>
                <span style={{fontSize:'1.25rem'}}>{item.icon}</span>
                <span style={{color:'#9aa3bf',fontSize:'0.875rem'}}>{item.text}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Right Panel */}
      <div style={{flex:1,display:'flex',alignItems:'center',justifyContent:'center',padding:'3rem'}}>
        <div style={{width:'100%',maxWidth:420}}>
          <div style={{marginBottom:'2rem'}}>
            <h2 style={{fontWeight:800,fontSize:'1.75rem',marginBottom:'0.5rem'}}>Welcome back</h2>
            <p style={{color:'#9aa3bf'}}>Sign in to your SIST SkillConnect account</p>
          </div>

          <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:16,padding:'2rem'}}>
            {error && <div style={{background:'#ff575720',border:'1px solid #ff5757',borderRadius:8,padding:'12px',marginBottom:'1rem',color:'#ff5757',fontSize:'0.875rem'}}>{error}</div>}

            <div style={{marginBottom:'1rem'}}>
              <label style={labelStyle}>College Email</label>
              <input value={form.email} onChange={e=>setForm({...form,email:e.target.value})} type="email" placeholder="yourname@sathyabama.ac.in" style={inputStyle} onKeyDown={e=>e.key==='Enter'&&handleSubmit(e)} />
            </div>
            <div style={{marginBottom:'1.5rem'}}>
              <label style={labelStyle}>Password</label>
              <input value={form.password} onChange={e=>setForm({...form,password:e.target.value})} type="password" placeholder="••••••••" style={inputStyle} onKeyDown={e=>e.key==='Enter'&&handleSubmit(e)} />
            </div>

            <button onClick={handleSubmit} disabled={loading} style={btnStyle}>
              {loading ? 'Signing in...' : 'Sign In →'}
            </button>
          </div>

          <p style={{textAlign:'center',marginTop:'1.5rem',color:'#9aa3bf',fontSize:'0.875rem'}}>
            New to SIST SkillConnect? <Link to="/register" style={{color:'#6c63ff',fontWeight:600}}>Create Account</Link>
          </p>

          <p style={{textAlign:'center',marginTop:'1rem',color:'#5c6580',fontSize:'0.75rem'}}>
            © 2026 Sathyabama Institute of Science and Technology
          </p>
        </div>
      </div>
    </div>
  );
}

const labelStyle = {display:'block',marginBottom:'6px',fontSize:'0.875rem',fontWeight:600,color:'#9aa3bf'};
const inputStyle = {width:'100%',padding:'11px 14px',background:'#0f1320',border:'1px solid #252d47',borderRadius:8,color:'#e8eaf0',fontSize:'0.9rem',outline:'none',boxSizing:'border-box'};
const btnStyle = {width:'100%',padding:'13px',background:'linear-gradient(135deg, #6c63ff, #8b85ff)',border:'none',borderRadius:10,color:'#fff',fontWeight:700,fontSize:'1rem',cursor:'pointer',letterSpacing:'0.02em'};
